import { Link } from 'react-router-dom';
import { FaUser, FaClock } from 'react-icons/fa';

function ForumPostCard({ post }) {
  // Format date
  const formatDate = (dateString) => {
    const options = { year: 'numeric', month: 'short', day: 'numeric' };
    return new Date(dateString).toLocaleDateString(undefined, options);
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-md mb-4 border border-gray-200 hover:shadow-lg transition-shadow">
      <Link to={`/forum/${post._id}`}>
        <h3 className="text-xl font-semibold text-green-700 mb-2">{post.title}</h3>
      </Link>
      <p className="text-gray-600 mb-4">
        {post.description.length > 150
          ? `${post.description.substring(0, 150)}...`
          : post.description}
      </p>
      <div className="flex justify-between items-center text-sm text-gray-500">
        <div className="flex items-center">
          <FaUser className="mr-1" />
          <span>{post.user?.name || 'Anonymous'}</span>
        </div>
        <div className="flex items-center">
          <FaClock className="mr-1" />
          <span>{formatDate(post.createdAt)}</span>
        </div>
        <div>
          <span className="bg-green-100 text-green-800 px-2 py-1 rounded-full text-xs">
            {post.comments.length} {post.comments.length === 1 ? 'comment' : 'comments'}
          </span>
        </div>
      </div>
    </div>
  );
}

export default ForumPostCard;
